from agent import *from models.products import *def run(context, session):    session.sessionbreakers = [SessionBreak(max_requests=3000)]    session.queue(Request('http://jeux-video.krinein.com/'), process_category, dict())def process_category(data, context, session):    prods = data.xpath("//div[@id='container']/a")    for prod in prods:        title = prod.xpath("@title").string()        url = prod.xpath("@href").string()        rate = prod.xpath("following::div[1][@class='note']//text()").string()        if rate:            session.queue(Request(url), process_product, dict(context, url=url, title=title, rate=rate))         next_url = data.xpath("//link[@rel='next']/@href").string()    if next_url:        session.queue(Request(next_url), process_category, dict(context))def process_product(data, context, session):    product = Product()    product.name = context['title'].split(' - ')[0].replace('Test', '')    prod_content = data.xpath("//div[@class='titre']")        if prod_content:        for content in prod_content:            following_elem = content.xpath("following::ul[1]/li//text()").string()            following_elem_href = content.xpath("following::ul[1]/li/a/@href").string()            if content.xpath("text()").string() == "Autre Plateforme":                product.category = "Games|" + following_elem            if content.xpath("text()").string() == "Développeur":                product.manufacturer = following_elem            if content.xpath("text()").string() == "Site officiel":                product.url = following_elem_href                product.ssid = following_elem_href.split('-')[-1].split('.')[0]                if following_elem_href.split('/')[2] == 'www.microsoft.com':                    product.ssid = following_elem_href.split('?')[0].split('/')[-1]                if not product.ssid.isdigit():                    product.ssid = following_elem_href.split('/')[-3]                if not product.ssid.isdigit():                    product.ssid = context['url'].split('/')[-2]            if content.xpath("text()").string() == "La presse en parle":                product.url = following_elem_href                product.ssid = following_elem_href.split('-')[0].split('/')[-1]    if not product.name:        product.name = data.xpath('//h1//text()').string().replace('Test - ', '')               if not product.url:        product.url = context['url']    if not product.ssid:        product.ssid = product.url.split('/')[-2]    if not product.category:        product.category = 'Games'    review = Review()    review.title = context['title']    review.date = data.xpath("//span[@class='dtreviewed']//text()").string()    review.type = 'pro'    review.url = context['url']    author_url = data.xpath('//div[@class="wrapper"]/a[1]/@href').string()    author_name = data.xpath('//div[@class="wrapper"]/a[1]/span[@class="reviewer"]//text()').string()    if author_url and author_name:        author_ssid = author_url.split('=')[-1]        review.authors.append(Person(name=author_name, url=author_url, ssid=author_ssid))    grade_overall = data.xpath('//span[@class="rating"]/span[@class="value"]//text()').string()    grade_best = data.xpath('//span[@class="rating"]/span[@class="best"]//text()').string()    if grade_overall:        review.grades.append(Grade(type='overall', value=float(grade_overall), best=float(grade_best)))    summary = data.xpath("//p[@class='chapo']//text()").string()    if summary:        review.add_property(type='summary', value=summary)    excerpt = data.xpath('//p[position() > 2]//text()').string(multiple=True)    if not excerpt:        excerpt = data.xpath('//p[position() > 1]//text()').string(multiple=True)    if excerpt:        review.add_property(type='excerpt', value=excerpt)        if author_name:            review.ssid = review.digest()         else:            review.ssid = review.digest(excerpt)        product.reviews.append(review)        session.emit(product)